import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { CULTO_TYPES, ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { CultoType } from '../types';

const CultoIniciar: React.FC = () => {
  const navigate = useNavigate();
  const [tipo, setTipo] = useState<CultoType>('Santa Ceia');
  const [tipoManual, setTipoManual] = useState('');
  const [responsaveis, setResponsaveis] = useState('');
  const [data, setData] = useState(new Date().toISOString().split('T')[0]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const active = await storageService.getActiveCulto();
    if (active) {
      alert('Já existe um culto ativo. Encerre-o antes de iniciar outro.');
      setIsSubmitting(false);
      return;
    }

    const newCulto = {
      tipo,
      tipoManual: tipo === 'Outros' ? tipoManual : undefined,
      data,
      horaInicio: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      responsaveis,
      status: 'ativo' as const
    };

    try {
      const docRef = await storageService.addCulto(newCulto);
      navigate(`/cultos/ativo/${docRef.id}`);
    } catch (error) {
      alert('Erro ao iniciar culto. Tente novamente.');
      setIsSubmitting(false);
    }
  };

  return (
    <div className="max-w-xl mx-auto animate-in zoom-in-95 duration-500">
      <button 
        onClick={() => navigate(-1)}
        className="mb-6 flex items-center gap-2 text-purple-main font-black uppercase tracking-widest text-[10px] hover:gap-3 transition-all"
      >
        {ICONS.ArrowLeft} Voltar
      </button>

      <div className="bg-white rounded-[2rem] shadow-xl overflow-hidden border-b-8 border-yellow-main">
        <div className="bg-purple-main p-6 md:p-8 text-white">
          <h1 className="text-xl md:text-2xl font-black mb-1 tracking-tight uppercase text-white">Iniciar Novo Culto</h1>
          <p className="text-white/70 font-medium text-xs">Defina os detalhes da sessão de hoje.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 md:p-8 space-y-6">
          <section>
            <label className="block text-[10px] font-black text-gray-text uppercase tracking-widest mb-3 px-1">Tipo de Celebração</label>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
              {CULTO_TYPES.map(t => (
                <button
                  key={t}
                  type="button"
                  onClick={() => setTipo(t as CultoType)}
                  className={`p-2.5 rounded-xl border-2 font-black transition-all text-[11px] uppercase tracking-wide ${
                    tipo === t 
                      ? 'bg-purple-main border-purple-main text-white shadow-md' 
                      : 'bg-white border-gray-100 text-gray-500 hover:border-purple-main/20'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </section>

          {tipo === 'Outros' && (
            <div className="animate-in fade-in slide-in-from-top-2 duration-300">
              <label className="block text-[10px] font-black text-gray-text uppercase tracking-widest mb-2 px-1">Nome do culto</label>
              <input
                type="text"
                required
                value={tipoManual}
                onChange={(e) => setTipoManual(e.target.value)}
                className="w-full bg-gray-light border-2 border-transparent focus:border-purple-main outline-none p-3 rounded-xl font-bold text-sm"
                placeholder="Ex: Congresso Kids"
              />
            </div>
          )}

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] font-black text-gray-text uppercase tracking-widest mb-2 px-1">Data</label>
              <input
                type="date"
                required
                value={data}
                onChange={(e) => setData(e.target.value)}
                className="w-full bg-gray-light border-2 border-transparent focus:border-purple-main outline-none p-3 rounded-xl font-bold text-sm"
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-gray-text uppercase tracking-widest mb-2 px-1">Início</label>
              <div className="w-full bg-gray-100 p-3 rounded-xl font-black text-sm text-gray-400 flex items-center gap-2">
                {ICONS.Clock} {new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-black text-gray-text uppercase tracking-widest mb-2 px-1">Responsáveis</label>
            <textarea
              required
              rows={2}
              value={responsaveis}
              onChange={(e) => setResponsaveis(e.target.value)}
              className="w-full bg-gray-light border-2 border-transparent focus:border-purple-main outline-none p-3 rounded-xl font-bold text-sm resize-none"
              placeholder="Tios e voluntários de hoje..."
            />
          </div>

          <button
            type="submit"
            disabled={isSubmitting}
            className="w-full bg-yellow-main hover:bg-yellow-secondary text-purple-dark font-black py-4 rounded-2xl shadow-lg transition-all transform active:scale-95 text-xs tracking-widest uppercase disabled:opacity-50"
          >
            {isSubmitting ? 'INICIANDO...' : 'ABRIR CHECK-IN AGORA'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default CultoIniciar;

import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { Culto } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  isAdmin: boolean;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, isAdmin, onLogout }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [activeCulto, setActiveCulto] = useState<Culto | null>(null);

  useEffect(() => {
    const unsubscribe = storageService.subscribeToActiveCulto((culto) => {
      setActiveCulto(culto);
    });
    return () => unsubscribe();
  }, []);

  const menuItems = [
    { label: 'Painel', path: '/', icon: ICONS.Dashboard },
    { label: 'Crianças', path: '/criancas', icon: ICONS.Baby },
    { label: 'Histórico', path: '/cultos', icon: ICONS.Calendar },
    { label: 'Estatísticas', path: '/estatisticas', icon: ICONS.BarChart },
  ];

  const isAtivoPage = location.pathname.includes('/cultos/ativo');

  if (!isAdmin || location.pathname.startsWith('/pais') || location.pathname === '/login') {
    return <div className="min-h-screen bg-gray-light font-sans">{children}</div>;
  }

  return (
    <div className="min-h-screen bg-gray-light flex flex-col md:flex-row">
      <aside className="hidden md:flex flex-col w-64 bg-purple-dark text-white sticky top-0 h-screen shadow-2xl z-40">
        <div className="p-6 border-b border-purple-main/20">
          <div className="flex items-center gap-3">
            <div className="bg-white p-2 rounded-xl shadow-lg">
              <img src="https://api.dicebear.com/7.x/shapes/svg?seed=ieadms" alt="Logo" className="w-8 h-8" />
            </div>
            <div>
              <h1 className="kids-font text-xl font-bold leading-tight text-white">IEADMS</h1>
              <span className="text-yellow-main font-black tracking-widest text-[11px] uppercase">Culto Kids</span>
            </div>
          </div>
        </div>

        <nav className="flex-1 py-8 px-4 space-y-1.5">
          {menuItems.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <Link
                key={item.path}
                to={item.path}
                className={`flex items-center gap-4 px-5 py-3.5 rounded-2xl transition-all duration-300 font-bold text-sm ${
                  isActive 
                    ? 'bg-purple-main text-white shadow-lg translate-x-1' 
                    : 'text-white/70 hover:bg-white/10 hover:text-white'
                }`}
              >
                <span className={isActive ? 'text-yellow-main' : 'opacity-80'}>{item.icon}</span>
                {item.label}
              </Link>
            );
          })}
        </nav>

        {activeCulto && (
          <div className="m-5 p-5 bg-green-500/10 border border-green-500/30 rounded-[2rem]">
            <div className="flex items-center gap-2 text-green-400 mb-1.5">
              <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
              <span className="text-[10px] font-black uppercase tracking-widest">Culto Ativo</span>
            </div>
            <p className="text-sm font-black mb-3 text-white truncate">{activeCulto.tipo}</p>
            <button 
              onClick={() => navigate(`/cultos/ativo/${activeCulto.id}`)}
              className="w-full bg-green-600 hover:bg-green-500 text-white py-2 rounded-xl text-[11px] font-black transition-colors uppercase tracking-tight"
            >
              GERENCIAR
            </button>
          </div>
        )}

        <button 
          onClick={onLogout}
          className="m-8 flex items-center gap-3 text-white/50 hover:text-red-400 transition-colors font-bold px-4 text-xs"
        >
          {ICONS.LogOut}
          <span>Sair</span>
        </button>
      </aside>

      <header className="md:hidden bg-purple-dark text-white p-4 flex items-center justify-between sticky top-0 z-50 shadow-xl">
        <div className="flex items-center gap-2">
          <div className="bg-white p-1 rounded-lg">
            <img src="https://api.dicebear.com/7.x/shapes/svg?seed=ieadms" alt="Logo" className="w-6 h-6" />
          </div>
          <span className="kids-font font-bold text-md">IEADMS Kids</span>
        </div>
        <button onClick={onLogout} className="text-white/60 p-2">{ICONS.LogOut}</button>
      </header>

      <main className="flex-1 p-6 md:p-10 pb-24 md:pb-10 max-w-[1300px] mx-auto w-full">
        {children}
      </main>

      {/* Botão Flutuante de Culto Ativo */}
      {activeCulto && !isAtivoPage && (
        <button
          onClick={() => navigate(`/cultos/ativo/${activeCulto.id}`)}
          className="fixed bottom-24 md:bottom-10 right-6 z-[60] bg-green-500 hover:bg-green-600 text-white p-4 md:p-5 rounded-full shadow-[0_10px_30px_rgba(34,197,94,0.4)] flex items-center gap-3 transition-all active:scale-90 group animate-bounce-slow"
        >
          <div className="w-3 h-3 bg-white rounded-full animate-pulse shadow-sm" />
          <span className="font-black text-xs md:text-sm uppercase tracking-widest pr-2">Culto Ativo</span>
        </button>
      )}

      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 flex justify-around py-3 px-4 z-50 shadow-[0_-5px_15px_rgba(0,0,0,0.05)]">
        {menuItems.map((item) => {
          const isActive = location.pathname === item.path;
          return (
            <Link
              key={item.path}
              to={item.path}
              className={`flex flex-col items-center gap-1 transition-colors ${
                isActive ? 'text-purple-main' : 'text-gray-400'
              }`}
            >
              {item.icon}
              <span className="text-[10px] font-black uppercase tracking-tight">{item.label}</span>
            </Link>
          );
        })}
      </nav>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { Crianca, CheckIn, Culto, PreCheckIn } from '../types';

const formatPhone = (value: string) => {
  if (!value) return value;
  const phoneNumber = value.replace(/[^\d]/g, '');
  const phoneNumberLength = phoneNumber.length;
  if (phoneNumberLength < 3) return phoneNumber;
  if (phoneNumberLength < 7) {
    return `(${phoneNumber.slice(0, 2)}) ${phoneNumber.slice(2)}`;
  }
  return `(${phoneNumber.slice(0, 2)}) ${phoneNumber.slice(2, 7)}-${phoneNumber.slice(7, 11)}`;
};

const CultoAtivo: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();

  const [culto, setCulto] = useState<Culto | null>(null);
  const [checkins, setCheckins] = useState<CheckIn[]>([]);
  const [allCriancas, setAllCriancas] = useState<Crianca[]>([]);
  const [preCheckins, setPreCheckins] = useState<PreCheckIn[]>([]);

  const [searchTerm, setSearchTerm] = useState('');
  const [codeQuery, setCodeQuery] = useState('KIDS-');
  const [showCheckout, setShowCheckout] = useState<CheckIn | null>(null);
  const [showEndConfirm, setShowEndConfirm] = useState(false);
  const [checkoutName, setCheckoutName] = useState('');
  const [loading, setLoading] = useState(true);

  const [isAddingNew, setIsAddingNew] = useState(false);
  const [newKidForm, setNewKidForm] = useState({ nome: '', sobrenome: '', dataNascimento: '', responsavelNome: '', whatsapp: '', observacoes: '' });
  const [labelData, setLabelData] = useState<{ kid: Crianca, checkin: CheckIn } | null>(null);

  useEffect(() => {
    if (!id) return;
    const loadBasics = async () => {
      const kids = await storageService.getCriancas();
      setAllCriancas(kids);
    };
    loadBasics();

    const unsubCulto = storageService.subscribeToActiveCulto((c) => {
      if (!c || c.id !== id) {
        storageService.getCultos().then(list => {
          const found = list.find(item => item.id === id);
          if (found) setCulto(found);
          else navigate('/cultos');
        });
      } else {
        setCulto(c);
      }
    });

    const unsubCheckins = storageService.subscribeToCheckins(id, (list) => {
      setCheckins(list);
      setLoading(false);
    });

    const unsubPre = storageService.subscribeToPreCheckins(setPreCheckins);

    return () => {
      unsubCulto();
      unsubCheckins();
      unsubPre();
    };
  }, [id, navigate]);

  const activeCheckins = checkins.filter(c => c.status === 'presente');
  const finishedCheckins = checkins.filter(c => c.status === 'saiu');

  const triggerLabelPrint = (kid: Crianca, checkin: CheckIn) => {
    setLabelData({ kid, checkin });
    setTimeout(() => {
        window.print();
        setLabelData(null);
    }, 500);
  };

  const handleCodeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let val = e.target.value.toUpperCase();
    if (!val.startsWith('KIDS-')) {
      val = 'KIDS-' + val.replace('KIDS-', '');
    }
    setCodeQuery(val);
  };

  const handleManualCheckin = async (kid: Crianca) => {
    if (activeCheckins.some(c => c.idCrianca === kid.id)) {
      alert(`${kid.nome} já está presente.`);
      return;
    }
    const newCheck: Omit<CheckIn, 'id'> = {
      idCrianca: kid.id,
      idCulto: id!,
      horaEntrada: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      status: 'presente'
    };
    try {
      await storageService.addCheckin(newCheck);
      const updatedCheckins = await storageService.getCheckins(id!);
      const lastCheck = updatedCheckins.find(c => c.idCrianca === kid.id && c.status === 'presente');
      if (lastCheck) triggerLabelPrint(kid, lastCheck);
      setSearchTerm('');
    } catch (e) {
      alert("Erro ao realizar check-in.");
    }
  };

  const handleQuickRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const newKid = await storageService.addCrianca({ ...newKidForm, createdAt: new Date().toISOString() });
      const kids = await storageService.getCriancas();
      setAllCriancas(kids);
      await handleManualCheckin(newKid);
      setIsAddingNew(false);
      setNewKidForm({ nome: '', sobrenome: '', dataNascimento: '', responsavelNome: '', whatsapp: '', observacoes: '' });
    } catch (error) {
      alert("Erro ao cadastrar criança.");
    }
  };

  const handleCodeCheckin = async () => {
    const code = codeQuery.trim().toUpperCase();
    const pre = preCheckins.find(p => p.codigo === code && p.status === 'pendente');
    if (!pre) { alert('Código inválido.'); return; }
    const kid = allCriancas.find(k => k.id === pre.idCrianca);
    if (kid) {
      await handleManualCheckin(kid);
      await storageService.updatePreCheckin(pre.id, { status: 'confirmado', dataHoraCheckin: new Date().toISOString() });
      setCodeQuery('KIDS-');
    }
  };

  const handleConfirmCheckout = async () => {
    if (!showCheckout || !checkoutName) return;
    await storageService.updateCheckin(showCheckout.id, {
      status: 'saiu',
      horaSaida: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      quemRetirou: checkoutName
    });
    setShowCheckout(null);
    setCheckoutName('');
  };

  const handleEndCulto = async () => {
    if (activeCheckins.length > 0) { 
        alert('Libere todas as crianças antes.'); 
        setShowEndConfirm(false);
        return; 
    }
    try {
        await storageService.updateCulto(id!, { 
            status: 'encerrado', 
            horaFim: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }) 
        });
        navigate('/cultos');
    } catch (e) {
        alert("Erro ao encerrar culto.");
    }
  };

  const filteredKids = searchTerm.length > 1 
    ? allCriancas.filter(k => (k.nome + ' ' + k.sobrenome).toLowerCase().includes(searchTerm.toLowerCase()))
    : [];

  if (loading) return <div className="text-center py-20 text-purple-main font-bold">Carregando dados...</div>;

  return (
    <div className="space-y-6 pb-12">
      {/* SEÇÃO OCULTA PARA IMPRESSÃO (ESTILO POST-IT) */}
      <div id="print-section" className="hidden flex-col items-center justify-center text-center p-4">
        {labelData && (
          <>
            <h1 className="text-3xl font-black mb-1" style={{ fontSize: '24pt' }}>{labelData.kid.nome.toUpperCase()}</h1>
            <h2 className="text-xl font-bold mb-4" style={{ fontSize: '16pt' }}>{labelData.kid.sobrenome.toUpperCase()}</h2>
            <div className="w-full border-t-2 border-black my-4"></div>
            <p className="text-xs font-black uppercase tracking-widest text-gray-500 mb-1">Responsável</p>
            <p className="text-lg font-black mb-4">{labelData.kid.responsavelNome}</p>
            <div className="w-full border-t border-black/20 my-2"></div>
            <p className="text-xs font-bold text-gray-400">
                {new Date(culto?.data || '').toLocaleDateString('pt-BR')} às {labelData.checkin.horaEntrada}
            </p>
          </>
        )}
      </div>

      <div className="print:hidden space-y-6">
        {/* Header Intermediário */}
        <div className="bg-white p-6 rounded-[2.5rem] shadow-xl border-l-[10px] border-green-500 flex items-center justify-between gap-6 sticky top-0 z-30">
            <div>
            <span className="text-[10px] font-black uppercase tracking-widest text-green-600 bg-green-50 px-3 py-1 rounded-full mb-2 inline-block">ATIVO AGORA</span>
            <h1 className="text-2xl font-black text-purple-dark uppercase truncate">
                {culto?.tipo === 'Outros' ? culto.tipoManual : culto?.tipo}
            </h1>
            </div>

            <div className="flex items-center gap-4">
            <div className="bg-purple-main px-6 py-3 rounded-2xl text-white text-center shadow-lg">
                <span className="text-2xl font-black block leading-none">{activeCheckins.length}</span>
                <span className="text-[9px] font-black uppercase tracking-widest opacity-80 mt-1">Crianças</span>
            </div>
            <button onClick={() => setShowEndConfirm(true)} className="bg-red-500 hover:bg-red-600 text-white font-black px-6 py-3 rounded-2xl text-xs flex items-center gap-3 transition-colors shadow-lg">
                {ICONS.LogOut} <span className="hidden sm:inline uppercase tracking-widest">ENCERRAR</span>
            </button>
            </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
            <div className="lg:col-span-4 space-y-6">
            <div className="bg-yellow-main p-7 rounded-[2rem] shadow-lg flex flex-col items-center">
                <h2 className="w-full text-base font-black text-purple-dark mb-4 uppercase flex items-center gap-3">
                {ICONS.QrCode} Confirmar Código
                </h2>
                <div className="flex bg-white rounded-xl overflow-hidden w-full border-4 border-white shadow-inner">
                <input 
                    type="text" 
                    placeholder="EX: KIDS-1234"
                    value={codeQuery}
                    onChange={handleCodeChange}
                    className="flex-1 min-w-0 p-4 font-black text-xl tracking-widest uppercase outline-none focus:bg-gray-50"
                />
                <button 
                    onClick={handleCodeCheckin} 
                    className="bg-purple-dark text-white px-6 font-black text-sm hover:bg-purple-main transition-colors uppercase whitespace-nowrap"
                >
                    OK
                </button>
                </div>
            </div>

            <div className="bg-white p-7 rounded-[2rem] shadow-sm border border-gray-100">
                <div className="flex items-center justify-between mb-5">
                <h2 className="text-base font-black text-purple-dark uppercase flex items-center gap-3">
                    {ICONS.Search} Busca Manual
                </h2>
                <button onClick={() => setIsAddingNew(true)} className="text-[10px] font-black uppercase text-purple-main bg-purple-main/10 px-3 py-1.5 rounded-xl hover:bg-purple-main hover:text-white transition-all">+ Novo</button>
                </div>
                <input 
                type="text" 
                placeholder="Nome da criança..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-gray-light p-4 rounded-xl font-bold mb-4 outline-none border-2 border-transparent focus:border-purple-main text-sm"
                />
                <div className="space-y-1.5 max-h-[220px] overflow-y-auto custom-scrollbar">
                {filteredKids.map(kid => (
                    <button 
                    key={kid.id}
                    onClick={() => handleManualCheckin(kid)}
                    className="w-full flex items-center justify-between p-3.5 hover:bg-purple-main/10 rounded-xl transition-all text-sm font-bold text-gray-700 group"
                    >
                    <span>{kid.nome} {kid.sobrenome}</span>
                    <span className="text-purple-main group-hover:scale-125 transition-transform">{ICONS.Plus}</span>
                    </button>
                ))}
                </div>
            </div>

            {/* Nova Seção: Checkouts Realizados */}
            <div className="bg-white p-7 rounded-[2rem] shadow-sm border border-gray-100">
                <h2 className="text-base font-black text-purple-dark mb-4 uppercase flex items-center gap-3">
                {ICONS.CheckCircle} Checkouts ({finishedCheckins.length})
                </h2>
                <div className="space-y-3 max-h-[300px] overflow-y-auto custom-scrollbar">
                    {finishedCheckins.map(check => {
                        const kid = allCriancas.find(k => k.id === check.idCrianca);
                        return (
                            <div key={check.id} className="p-4 bg-gray-50 rounded-2xl border border-gray-100">
                                <p className="font-black text-xs text-purple-dark">{kid?.nome} {kid?.sobrenome}</p>
                                <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mt-1">
                                    Saiu às {check.horaSaida} com {check.quemRetirou}
                                </p>
                            </div>
                        );
                    })}
                    {finishedCheckins.length === 0 && (
                        <p className="text-center py-6 text-gray-300 font-bold text-[10px] uppercase tracking-widest italic">Nenhuma saída ainda.</p>
                    )}
                </div>
            </div>
            </div>

