import { createClient } from '@supabase/supabase-js';
import { supabaseConfig } from './supabaseConfig';
import { Crianca, Culto, CheckIn, PreCheckIn, NotificacaoAtiva } from '../types';

const PROJECT_SCHEMA = "kids_ieadms";

export const supabase = createClient(supabaseConfig.url, supabaseConfig.anonKey, {
  db: { 
    schema: PROJECT_SCHEMA 
  }
});

const TABLES = {
  CRIANCAS: 'criancas',
  CULTOS: 'cultos',
  CHECKINS: 'checkins',
  PRECHECKINS: 'pre_checkins',
  NOTIFICACOES: 'notificacoes_ativas'
};

const handleError = (error: any, context: string) => {
  if (error?.code === '42501' || error?.message?.includes('permission denied')) {
    console.error(`🔐 ERRO DE PERMISSÃO EM ${context}: Execute o comando GRANT no SQL Editor para o schema '${PROJECT_SCHEMA}'.`);
  } else if (error?.code === '42P01') {
    console.error(`❌ TABELA NÃO ENCONTRADA EM ${context}: Verifique se a tabela existe no schema '${PROJECT_SCHEMA}'.`);
  } else {
    console.error(`❌ Erro em ${context}:`, error);
  }
  return null;
};

export const storageService = {
  getCriancas: async () => {
    try {
      const { data, error } = await supabase.from(TABLES.CRIANCAS).select('*').order('nome', { ascending: true });
      if (error) throw error;
      return (data || []).map((d: any) => ({
        id: d.id, nome: d.nome, sobrenome: d.sobrenome, dataNascimento: d.data_nascimento,
        responsavelNome: d.responsavel_nome, whatsapp: d.whatsapp, observacoes: d.observacoes, createdAt: d.created_at
      } as Crianca));
    } catch (e) { handleError(e, 'getCriancas'); return []; }
  },

  addCrianca: async (c: Omit<Crianca, 'id'>) => {
    try {
      const { data, error } = await supabase.from(TABLES.CRIANCAS).insert([{
        nome: c.nome, sobrenome: c.sobrenome, data_nascimento: c.dataNascimento,
        responsavel_nome: c.responsavelNome, whatsapp: c.whatsapp, observacoes: c.observacoes
      }]).select();
      if (error) throw error;
      return data[0];
    } catch (e) { handleError(e, 'addCrianca'); throw e; }
  },

  getCultos: async () => {
    try {
      const { data, error } = await supabase.from(TABLES.CULTOS).select('*').order('data', { ascending: false });
      if (error) throw error;
      return (data || []).map((d: any) => ({
        id: d.id, tipo: d.tipo, tipoManual: d.tipo_manual, data: d.data,
        horaInicio: d.hora_inicio, horaFim: d.hora_fim, responsaveis: d.responsaveis, status: d.status
      } as Culto));
    } catch (e) { handleError(e, 'getCultos'); return []; }
  },

  getActiveCulto: async () => {
    try {
      const { data, error } = await supabase.from(TABLES.CULTOS).select('*').eq('status', 'ativo').limit(1).maybeSingle();
      if (error) throw error;
      if (!data) return null;
      return {
        id: data.id, tipo: data.tipo, tipoManual: data.tipo_manual, data: data.data,
        horaInicio: data.hora_inicio, horaFim: data.hora_fim, responsaveis: data.responsaveis, status: data.status
      } as Culto;
    } catch (e) { handleError(e, 'getActiveCulto'); return null; }
  },

  subscribeToActiveCulto: (callback: (culto: Culto | null) => void) => {
    storageService.getActiveCulto().then(callback);
    const channel = supabase.channel('active_culto_changes')
      .on('postgres_changes', { event: '*', schema: PROJECT_SCHEMA, table: TABLES.CULTOS }, () => {
        storageService.getActiveCulto().then(callback);
      }).subscribe();
    return () => { supabase.removeChannel(channel); };
  },

  addCulto: async (c: Omit<Culto, 'id'>) => {
    try {
      const { data, error } = await supabase.from(TABLES.CULTOS).insert([{
        tipo: c.tipo, tipo_manual: c.tipoManual, data: c.data, hora_inicio: c.horaInicio,
        responsaveis: c.responsaveis, status: 'ativo'
      }]).select();
      if (error) throw error;
      return data[0];
    } catch (e) { handleError(e, 'addCulto'); throw e; }
  },

  updateCulto: async (id: string, updated: Partial<Culto>) => {
    try {
      const payload: any = {};
      if (updated.status) payload.status = updated.status;
      if (updated.horaFim) payload.hora_fim = updated.horaFim;
      const { error } = await supabase.from(TABLES.CULTOS).update(payload).eq('id', id);
      if (error) throw error;
    } catch (e) { handleError(e, 'updateCulto'); throw e; }
  },

  getCheckins: async (idCulto: string) => {
    try {
      const { data, error } = await supabase.from(TABLES.CHECKINS).select('*').eq('id_culto', idCulto);
      if (error) throw error;
      return (data || []).map((d: any) => ({
        id: d.id, idCrianca: d.id_crianca, idCulto: d.id_culto, horaEntrada: d.hora_entrada,
        horaSaida: d.hora_saida, quemRetirou: d.quem_retirou, status: d.status
      } as CheckIn));
    } catch (e) { handleError(e, 'getCheckins'); return []; }
  },

  getAllCheckins: async () => {
    try {
      const { data, error } = await supabase.from(TABLES.CHECKINS).select('*');
      if (error) throw error;
      return (data || []).map((d: any) => ({
        id: d.id, idCrianca: d.id_crianca, idCulto: d.id_culto, horaEntrada: d.hora_entrada,
        horaSaida: d.hora_saida, quemRetirou: d.quem_retirou, status: d.status
      } as CheckIn));
    } catch (e) { handleError(e, 'getAllCheckins'); return []; }
  },

  subscribeToCheckins: (idCulto: string, callback: (checkins: CheckIn[]) => void) => {
    storageService.getCheckins(idCulto).then(callback);
    const channel = supabase.channel(`checkins_${idCulto}`)
      .on('postgres_changes', { event: '*', schema: PROJECT_SCHEMA, table: TABLES.CHECKINS, filter: `id_culto=eq.${idCulto}` }, () => {
        storageService.getCheckins(idCulto).then(callback);
      }).subscribe();
    return () => { supabase.removeChannel(channel); };
  },

  addCheckin: async (c: Omit<CheckIn, 'id'>) => {
    try {
      const { error } = await supabase.from(TABLES.CHECKINS).insert([{
        id_crianca: c.idCrianca, id_culto: c.idCulto, hora_entrada: c.horaEntrada, status: 'presente'
      }]);
      if (error) throw error;
    } catch (e) { handleError(e, 'addCheckin'); throw e; }
  },

  updateCheckin: async (id: string, updated: Partial<CheckIn>) => {
    try {
      const payload: any = {};
      if (updated.status) payload.status = updated.status;
      if (updated.horaSaida) payload.hora_saida = updated.horaSaida;
      if (updated.quemRetirou) payload.quem_retirou = updated.quemRetirou;
      const { error } = await supabase.from(TABLES.CHECKINS).update(payload).eq('id', id);
      if (error) throw error;
    } catch (e) { handleError(e, 'updateCheckin'); throw e; }
  },

  getPreCheckins: async () => {
    try {
      const { data, error } = await supabase.from(TABLES.PRECHECKINS).select('*');
      if (error) throw error;
      return (data || []).map((d: any) => ({
        id: d.id, idCrianca: d.id_crianca, idCulto: d.id_culto, codigo: d.codigo,
        status: d.status, dataHoraPreCheckin: d.data_hora_pre_checkin, dataHoraCheckin: d.data_hora_checkin
      } as PreCheckIn));
    } catch (e) { handleError(e, 'getPreCheckins'); return []; }
  },

  subscribeToPreCheckins: (callback: (pre: PreCheckIn[]) => void) => {
    storageService.getPreCheckins().then(callback);
    const channel = supabase.channel('pre_checkins_changes')
      .on('postgres_changes', { event: '*', schema: PROJECT_SCHEMA, table: TABLES.PRECHECKINS }, () => {
        storageService.getPreCheckins().then(callback);
      }).subscribe();
    return () => { supabase.removeChannel(channel); };
  },

  addPreCheckin: async (p: Omit<PreCheckIn, 'id'>) => {
    try {
      const { error } = await supabase.from(TABLES.PRECHECKINS).insert([{
        id_crianca: p.idCrianca, id_culto: p.idCulto, codigo: p.codigo, status: 'pendente'
      }]);
      if (error) throw error;
    } catch (e) { handleError(e, 'addPreCheckin'); throw e; }
  },

  updatePreCheckin: async (id: string, updated: Partial<PreCheckIn>) => {
    try {
      const payload: any = {};
      if (updated.status) payload.status = updated.status;
      if (updated.dataHoraCheckin) payload.data_hora_checkin = updated.dataHoraCheckin;
      const { error } = await supabase.from(TABLES.PRECHECKINS).update(payload).eq('id', id);
      if (error) throw error;
    } catch (e) { handleError(e, 'updatePreCheckin'); throw e; }
  },

  // MÉTODOS DE NOTIFICAÇÃO TEMPORÁRIA
  sendNotificacao: async (idCrianca: string, idCulto: string) => {
    try {
      const { error } = await supabase.from(TABLES.NOTIFICACOES).insert([{
        id_crianca: idCrianca,
        id_culto: idCulto,
        mensagem: 'Papai/Mamãe sua criança está te aguardando para o Checkout'
      }]);
      if (error) throw error;
    } catch (e) { handleError(e, 'sendNotificacao'); }
  },

  clearNotificacoes: async (idCulto: string) => {
    try {
      const { error } = await supabase.from(TABLES.NOTIFICACOES).delete().eq('id_culto', idCulto);
      if (error) throw error;
    } catch (e) { handleError(e, 'clearNotificacoes'); }
  },

  subscribeToNotificacoes: (idCrianca: string, callback: (n: any) => void) => {
    const channel = supabase.channel(`notificacao_${idCrianca}`)
      .on('postgres_changes', { 
        event: 'INSERT', 
        schema: PROJECT_SCHEMA, 
        table: TABLES.NOTIFICACOES,
        filter: `id_crianca=eq.${idCrianca}` 
      }, (payload) => {
        callback(payload.new);
      }).subscribe();
    return () => { supabase.removeChannel(channel); };
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { Crianca, CheckIn, Culto, PreCheckIn } from '../types';

const formatPhone = (value: string) => {
  if (!value) return value;
  const phoneNumber = value.replace(/[^\d]/g, '');
  const phoneNumberLength = phoneNumber.length;
  if (phoneNumberLength < 3) return phoneNumber;
  if (phoneNumberLength < 7) {
    return `(${phoneNumber.slice(0, 2)}) ${phoneNumber.slice(2)}`;
  }
  return `(${phoneNumber.slice(0, 2)}) ${phoneNumber.slice(2, 7)}-${phoneNumber.slice(7, 11)}`;
};

const CultoAtivo: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();

  const [culto, setCulto] = useState<Culto | null>(null);
  const [checkins, setCheckins] = useState<CheckIn[]>([]);
  const [allCriancas, setAllCriancas] = useState<Crianca[]>([]);
  const [preCheckins, setPreCheckins] = useState<PreCheckIn[]>([]);

  const [searchTerm, setSearchTerm] = useState('');
  const [codeQuery, setCodeQuery] = useState('KIDS-');
  const [showCheckout, setShowCheckout] = useState<CheckIn | null>(null);
  const [showEndConfirm, setShowEndConfirm] = useState(false);
  const [checkoutName, setCheckoutName] = useState('');
  const [loading, setLoading] = useState(true);

  const [isAddingNew, setIsAddingNew] = useState(false);
  const [newKidForm, setNewKidForm] = useState({ nome: '', sobrenome: '', dataNascimento: '', responsavelNome: '', whatsapp: '', observacoes: '' });
  const [labelData, setLabelData] = useState<{ kid: Crianca, checkin: CheckIn } | null>(null);

  useEffect(() => {
    if (!id) return;
    const loadBasics = async () => {
      const kids = await storageService.getCriancas();
      setAllCriancas(kids);
    };
    loadBasics();

    const unsubCulto = storageService.subscribeToActiveCulto((c) => {
      if (!c || c.id !== id) {
        storageService.getCultos().then(list => {
          const found = list.find(item => item.id === id);
          if (found) setCulto(found);
          else navigate('/cultos');
        });
      } else {
        setCulto(c);
      }
    });

    const unsubCheckins = storageService.subscribeToCheckins(id, (list) => {
      setCheckins(list);
      setLoading(false);
    });

    const unsubPre = storageService.subscribeToPreCheckins(setPreCheckins);

    return () => {
      unsubCulto();
      unsubCheckins();
      unsubPre();
    };
  }, [id, navigate]);

  const activeCheckins = checkins.filter(c => c.status === 'presente');
  const finishedCheckins = checkins.filter(c => c.status === 'saiu');

  const triggerLabelPrint = (kid: Crianca, checkin: CheckIn) => {
    setLabelData({ kid, checkin });
    setTimeout(() => {
        window.print();
        setLabelData(null);
    }, 500);
  };

  const handleSendNotification = async (kidId: string) => {
    if (!id) return;
    await storageService.sendNotificacao(kidId, id);
    alert('Notificação enviada ao celular do responsável!');
  };

  const handleCodeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let val = e.target.value.toUpperCase();
    if (!val.startsWith('KIDS-')) {
      val = 'KIDS-' + val.replace('KIDS-', '');
    }
    setCodeQuery(val);
  };

  const handleManualCheckin = async (kid: Crianca) => {
    if (activeCheckins.some(c => c.idCrianca === kid.id)) {
      alert(`${kid.nome} já está presente.`);
      return;
    }
    const newCheck: Omit<CheckIn, 'id'> = {
      idCrianca: kid.id,
      idCulto: id!,
      horaEntrada: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      status: 'presente'
    };
    try {
      await storageService.addCheckin(newCheck);
      const updatedCheckins = await storageService.getCheckins(id!);
      const lastCheck = updatedCheckins.find(c => c.idCrianca === kid.id && c.status === 'presente');
      if (lastCheck) triggerLabelPrint(kid, lastCheck);
      setSearchTerm('');
    } catch (e) {
      alert("Erro ao realizar check-in.");
    }
  };

  const handleQuickRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const newKid = await storageService.addCrianca({ ...newKidForm, createdAt: new Date().toISOString() });
      const kids = await storageService.getCriancas();
      setAllCriancas(kids);
      await handleManualCheckin(newKid);
      setIsAddingNew(false);
      setNewKidForm({ nome: '', sobrenome: '', dataNascimento: '', responsavelNome: '', whatsapp: '', observacoes: '' });
    } catch (error) {
      alert("Erro ao cadastrar criança.");
    }
  };

  const handleCodeCheckin = async () => {
    const code = codeQuery.trim().toUpperCase();
    const pre = preCheckins.find(p => p.codigo === code && p.status === 'pendente');
    if (!pre) { alert('Código inválido.'); return; }
    const kid = allCriancas.find(k => k.id === pre.idCrianca);
    if (kid) {
      await handleManualCheckin(kid);
      await storageService.updatePreCheckin(pre.id, { status: 'confirmado', dataHoraCheckin: new Date().toISOString() });
      setCodeQuery('KIDS-');
    }
  };

  const handleConfirmCheckout = async () => {
    if (!showCheckout || !checkoutName) return;
    await storageService.updateCheckin(showCheckout.id, {
      status: 'saiu',
      horaSaida: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      quemRetirou: checkoutName
    });
    setShowCheckout(null);
    setCheckoutName('');
  };

  const handleEndCulto = async () => {
    if (activeCheckins.length > 0) { 
        alert('Libere todas as crianças antes.'); 
        setShowEndConfirm(false);
        return; 
    }
    try {
        // LIMPEZA DAS NOTIFICAÇÕES TEMPORÁRIAS DO CULTO
        await storageService.clearNotificacoes(id!);

        await storageService.updateCulto(id!, { 
            status: 'encerrado', 
            horaFim: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }) 
        });
        navigate('/cultos');
    } catch (e) {
        alert("Erro ao encerrar culto.");
    }
  };

  const filteredKids = searchTerm.length > 1 
    ? allCriancas.filter(k => (k.nome + ' ' + k.sobrenome).toLowerCase().includes(searchTerm.toLowerCase()))
    : [];

  if (loading) return <div className="text-center py-20 text-purple-main font-bold">Carregando dados...</div>;

  return (
    <div className="space-y-6 pb-12">
      {/* SEÇÃO OCULTA PARA IMPRESSÃO (ESTILO POST-IT 80x80mm) */}
      <div id="print-section" className="hidden flex-col items-center justify-center text-center p-4">
        {labelData && (
          <div className="flex flex-col items-center w-full">
            <h1 className="font-black leading-tight uppercase" style={{ fontSize: '28pt' }}>{labelData.kid.nome}</h1>
            <h2 className="font-bold leading-tight uppercase opacity-70" style={{ fontSize: '18pt' }}>{labelData.kid.sobrenome}</h2>
            <div className="w-full border-t-2 border-black my-6"></div>
            <div className="text-center">
                <p className="text-xs font-black uppercase tracking-widest text-gray-400 mb-1">Responsável</p>
                <p className="font-black" style={{ fontSize: '14pt' }}>{labelData.kid.responsavelNome}</p>
            </div>
            <div className="w-full border-t border-black/20 my-4"></div>
            <p className="font-bold text-gray-500" style={{ fontSize: '10pt' }}>
                Entrada: {new Date(culto?.data || '').toLocaleDateString('pt-BR')} às {labelData.checkin.horaEntrada}
            </p>
          </div>
        )}
      </div>

      <div className="print:hidden space-y-6">
        {/* Header Intermediário */}
        <div className="bg-white p-6 rounded-[2.5rem] shadow-xl border-l-[10px] border-green-500 flex items-center justify-between gap-6 sticky top-0 z-30">
            <div>
            <span className="text-[10px] font-black uppercase tracking-widest text-green-600 bg-green-50 px-3 py-1 rounded-full mb-2 inline-block">ATIVO AGORA</span>
            <h1 className="text-2xl font-black text-purple-dark uppercase truncate">
                {culto?.tipo === 'Outros' ? culto.tipoManual : culto?.tipo}
            </h1>
            </div>

            <div className="flex items-center gap-4">
            <div className="bg-purple-main px-6 py-3 rounded-2xl text-white text-center shadow-lg">
                <span className="text-2xl font-black block leading-none">{activeCheckins.length}</span>
                <span className="text-[9px] font-black uppercase tracking-widest opacity-80 mt-1">Crianças</span>
            </div>
            <button onClick={() => setShowEndConfirm(true)} className="bg-red-500 hover:bg-red-600 text-white font-black px-6 py-3 rounded-2xl text-xs flex items-center gap-3 transition-colors shadow-lg">
                {ICONS.LogOut} <span className="hidden sm:inline uppercase tracking-widest">ENCERRAR</span>
            </button>
            </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
            <div className="lg:col-span-4 space-y-6">
            <div className="bg-yellow-main p-7 rounded-[2rem] shadow-lg flex flex-col items-center">
                <h2 className="w-full text-base font-black text-purple-dark mb-4 uppercase flex items-center gap-3">
                {ICONS.QrCode} Confirmar Código
                </h2>
                <div className="flex bg-white rounded-xl overflow-hidden w-full border-4 border-white shadow-inner">
                <input 
                    type="text" 
                    placeholder="EX: KIDS-1234"
                    value={codeQuery}
                    onChange={handleCodeChange}
                    className="flex-1 min-w-0 p-4 font-black text-xl tracking-widest uppercase outline-none focus:bg-gray-50"
                />
                <button 
                    onClick={handleCodeCheckin} 
                    className="bg-purple-dark text-white px-6 font-black text-sm hover:bg-purple-main transition-colors uppercase whitespace-nowrap"
                >
                    OK
                </button>
                </div>
            </div>

            <div className="bg-white p-7 rounded-[2rem] shadow-sm border border-gray-100">
                <div className="flex items-center justify-between mb-5">
                <h2 className="text-base font-black text-purple-dark uppercase flex items-center gap-3">
                    {ICONS.Search} Busca Manual
                </h2>
                <button onClick={() => setIsAddingNew(true)} className="text-[10px] font-black uppercase text-purple-main bg-purple-main/10 px-3 py-1.5 rounded-xl hover:bg-purple-main hover:text-white transition-all">+ Novo</button>
                </div>
                <input 
                type="text" 
                placeholder="Nome da criança..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-gray-light p-4 rounded-xl font-bold mb-4 outline-none border-2 border-transparent focus:border-purple-main text-sm"
                />
                <div className="space-y-1.5 max-h-[220px] overflow-y-auto custom-scrollbar">
                {filteredKids.map(kid => (
                    <button 
                    key={kid.id}
                    onClick={() => handleManualCheckin(kid)}
                    className="w-full flex items-center justify-between p-3.5 hover:bg-purple-main/10 rounded-xl transition-all text-sm font-bold text-gray-700 group"
                    >
                    <span>{kid.nome} {kid.sobrenome}</span>
                    <span className="text-purple-main group-hover:scale-125 transition-transform">{ICONS.Plus}</span>
                    </button>
                ))}
                </div>
            </div>

            <div className="bg-white p-7 rounded-[2rem] shadow-sm border border-gray-100">
                <div className="flex items-center justify-between mb-4">
                    <h2 className="text-base font-black text-purple-dark uppercase flex items-center gap-3">
                        {ICONS.CheckCircle} Checkouts Realizados
                    </h2>
                    <span className="bg-gray-light text-gray-400 px-3 py-1 rounded-full text-[10px] font-black">{finishedCheckins.length}</span>
                </div>
                <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar">
                    {finishedCheckins.map(check => {
                        const kid = allCriancas.find(k => k.id === check.idCrianca);
                        return (
                            <div key={check.id} className="p-4 bg-gray-50 rounded-2xl border border-gray-100 hover:bg-white hover:shadow-md transition-all group">
                                <div className="flex justify-between items-start mb-1">
                                    <h4 className="font-black text-xs text-purple-dark truncate mr-2">{kid?.nome} {kid?.sobrenome}</h4>
                                    <span className="text-[9px] font-black text-purple-main bg-purple-main/10 px-2 py-0.5 rounded-full">{check.horaSaida}</span>
                                </div>
                                <div className="flex items-center gap-1.5 text-gray-400">
                                    <span className="text-[9px] font-black uppercase tracking-widest">Retirado por:</span>
                                    <span className="text-[10px] font-bold text-gray-600 truncate">{check.quemRetirou}</span>
                                </div>
                            </div>
                        );
                    })}
                    {finishedCheckins.length === 0 && (
                        <div className="py-10 text-center text-gray-300">
                            <p className="text-[10px] font-black uppercase tracking-widest italic leading-relaxed">Nenhuma criança<br/>saiu ainda hoje.</p>
                        </div>
                    )}
                </div>
            </div>
            </div>

            <div className="lg:col-span-8">
            <div className="bg-white p-7 rounded-[2rem] shadow-sm border border-gray-100 min-h-[450px]">
                <h2 className="text-base font-black text-purple-dark mb-6 uppercase flex items-center gap-3">
                {ICONS.Baby} Crianças na Sala ({activeCheckins.length})
                </h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {activeCheckins.map(check => {
                    const kid = allCriancas.find(k => k.id === check.idCrianca);
                    return (
                    <div key={check.id} className="bg-gray-light p-5 rounded-[1.5rem] flex flex-col justify-between border-2 border-transparent hover:border-purple-main/20 transition-all shadow-sm">
                        <div className="flex justify-between items-start mb-4">
                          <div className="flex-1 overflow-hidden mr-3">
                              <h4 className="font-black text-purple-dark text-base truncate leading-tight">{kid?.nome} {kid?.sobrenome}</h4>
                              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">Entrada: {check.horaEntrada}</p>
                          </div>

                          {/* AÇÕES DA CRIANÇA NO CULTO */}
                          <div className="flex flex-col gap-2">
                            <button onClick={() => triggerLabelPrint(kid!, check)} className="text-purple-main p-2.5 bg-white rounded-xl shadow-sm hover:bg-purple-main hover:text-white transition-all">
                              {ICONS.QrCode}
                            </button>
                            <button 
                              onClick={() => handleSendNotification(kid!.id)}
                              className="text-yellow-600 p-2.5 bg-white rounded-xl shadow-sm hover:bg-yellow-main hover:text-purple-dark transition-all"
                              title="Notificar Responsável"
                            >
                              <div className="animate-pulse">{ICONS.Info}</div>
                            </button>
                            <a 
                              href={`https://wa.me/${kid?.whatsapp.replace(/[^\d]/g, '')}?text=Olá, ${kid?.responsavelNome}. Sua criança ${kid?.nome} está te aguardando no Culto Kids para o checkout.`}
                              target="_blank"
                              className="text-white p-2.5 bg-green-500 rounded-xl shadow-sm hover:bg-green-600 transition-all text-center"
                              title="WhatsApp do Responsável"
                            >
                              {ICONS.Phone}
                            </a>
                          </div>
                        </div>
                        <button onClick={() => setShowCheckout(check)} className="w-full bg-white text-purple-main border-2 border-purple-main/20 hover:border-purple-main hover:bg-purple-main hover:text-white py-2.5 rounded-xl font-black text-[11px] transition-all uppercase tracking-widest shadow-sm">REALIZAR SAÍDA</button>
                    </div>
                    );
                })}
                {activeCheckins.length === 0 && (
                    <div className="col-span-full py-20 text-center text-gray-300 font-bold uppercase tracking-widest">Nenhuma criança na sala no momento.</div>
                )}
                </div>
            </div>
            </div>
        </div>

        {/* Modal Cadastro Rápido */}
        {isAddingNew && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-purple-dark/70 backdrop-blur-md">
            <div className="bg-white w-full max-w-lg rounded-[2rem] p-8 shadow-2xl animate-in zoom-in duration-300">
                <h2 className="text-xl font-black text-purple-dark mb-6 uppercase tracking-tight">Novo Cadastro Rápido</h2>
                <form onSubmit={handleQuickRegister} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                    <input required placeholder="Nome" value={newKidForm.nome} onChange={e => setNewKidForm({...newKidForm, nome: e.target.value})} className="bg-gray-light p-4 rounded-xl font-bold text-sm" />
                    <input required placeholder="Sobrenome" value={newKidForm.sobrenome} onChange={e => setNewKidForm({...newKidForm, sobrenome: e.target.value})} className="bg-gray-light p-4 rounded-xl font-bold text-sm" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <input required type="date" value={newKidForm.dataNascimento} onChange={e => setNewKidForm({...newKidForm, dataNascimento: e.target.value})} className="bg-gray-light p-4 rounded-xl font-bold text-sm" />
                    <input required placeholder="Responsável" value={newKidForm.responsavelNome} onChange={e => setNewKidForm({...newKidForm, responsavelNome: e.target.value})} className="bg-gray-light p-4 rounded-xl font-bold text-sm" />
                </div>
                <input required placeholder="WhatsApp (DDD + Número)" value={newKidForm.whatsapp} onChange={e => setNewKidForm({...newKidForm, whatsapp: formatPhone(e.target.value)})} className="w-full bg-gray-light p-4 rounded-xl font-bold text-sm" />
                <div className="grid grid-cols-2 gap-4 pt-4">
                    <button type="button" onClick={() => setIsAddingNew(false)} className="bg-gray-100 text-gray-500 font-black py-4 rounded-2xl text-xs uppercase tracking-widest">CANCELAR</button>
                    <button type="submit" className="bg-purple-main text-white font-black py-4 rounded-2xl shadow-xl text-xs uppercase tracking-widest">SALVAR E ENTRAR</button>
                </div>
                </form>
            </div>
            </div>
        )}

        {/* Modal Saída */}
        {showCheckout && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-purple-dark/70 backdrop-blur-md">
            <div className="bg-white w-full max-sm rounded-[2rem] p-8 shadow-2xl text-center animate-in zoom-in duration-300">
                <h2 className="text-xl font-black text-purple-dark mb-2 uppercase tracking-tight">Confirmar Saída</h2>
                <p className="text-sm font-bold text-gray-500 mb-8 px-4">Quem veio buscar {allCriancas.find(k => k.id === showCheckout.idCrianca)?.nome}?</p>
                <input type="text" placeholder="Nome do responsável..." autoFocus value={checkoutName} onChange={(e) => setCheckoutName(e.target.value)} className="w-full bg-gray-light p-5 rounded-2xl font-bold mb-8 outline-none border-2 border-transparent focus:border-purple-main text-sm" />
                <div className="grid grid-cols-2 gap-4">
                <button onClick={() => setShowCheckout(null)} className="bg-gray-100 text-gray-500 font-black py-5 rounded-2xl text-xs tracking-widest">VOLTAR</button>
                <button onClick={handleConfirmCheckout} disabled={!checkoutName} className="bg-green-500 text-white font-black py-5 rounded-2xl shadow-xl disabled:opacity-50 text-xs uppercase tracking-widest">CONFIRMAR</button>
                </div>
            </div>
            </div>
        )}

        {/* Modal Encerrar */}
        {showEndConfirm && (
            <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-red-900/80 backdrop-blur-md">
            <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-10 shadow-2xl text-center animate-in zoom-in duration-300 border-t-8 border-red-500">
                <div className="bg-red-100 text-red-500 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6 text-2xl">
                    {ICONS.LogOut}
                </div>
                <h2 className="text-2xl font-black text-purple-dark mb-3 uppercase">ENCERRAR CULTO?</h2>
                <p className="text-gray-text font-bold mb-10 text-sm">Esta ação finalizará o registro de todas as atividades de hoje.</p>
                <div className="flex flex-col gap-3">
                    <button 
                        onClick={handleEndCulto}
                        className="w-full bg-red-500 text-white font-black py-5 rounded-2xl shadow-xl shadow-red-500/20 text-xs uppercase tracking-widest hover:bg-red-600 transition-colors"
                    >
                        SIM, ENCERRAR AGORA
                    </button>
                    <button 
                        onClick={() => setShowEndConfirm(false)}
                        className="w-full bg-gray-100 text-gray-500 font-black py-4 rounded-2xl text-xs uppercase tracking-widest hover:bg-gray-200 transition-colors"
                    >
                        NÃO, VOLTAR
                    </button>
                </div>
            </div>
            </div>
        )}
      </div>
    </div>
  );
};

export default CultoAtivo;

import React, { useState, useEffect } from 'react';
import { useNavigate, Navigate } from 'react-router-dom';
import { ICONS } from '../constants';
import { storageService } from '../services/storageService';
import { PreCheckIn, Crianca, Culto } from '../types';

const PreCheckin: React.FC = () => {
  const navigate = useNavigate();
  const [activeCulto, setActiveCulto] = useState<Culto | null>(null);
  const [kids, setKids] = useState<Crianca[]>([]);
  const [preCheckins, setPreCheckins] = useState<PreCheckIn[]>([]);
  const [loading, setLoading] = useState(true);

  const [search, setSearch] = useState('');
  const [step, setStep] = useState(1);
  const [generated, setGenerated] = useState<string | null>(null);
  const [selectedKidId, setSelectedKidId] = useState<string | null>(null);
  const [notificationsEnabled, setNotificationsEnabled] = useState(false);

  useEffect(() => {
    const loadData = async () => {
      const [culto, allKids, allPres] = await Promise.all([
        storageService.getActiveCulto(),
        storageService.getCriancas(),
        storageService.getPreCheckins()
      ]);
      setActiveCulto(culto);
      setKids(allKids);
      setPreCheckins(allPres);
      setLoading(false);
    };
    loadData();

    // Check if notifications already granted
    if (window.Notification && Notification.permission === 'granted') {
      setNotificationsEnabled(true);
    }
  }, []);

  // Listener para notificações quando uma criança é selecionada
  useEffect(() => {
    if (selectedKidId && notificationsEnabled) {
      const unsub = storageService.subscribeToNotificacoes(selectedKidId, (n) => {
        if (window.Notification && Notification.permission === 'granted') {
          new Notification('IEADMS Kids', {
            body: n.mensagem,
            icon: 'https://api.dicebear.com/7.x/shapes/svg?seed=kids'
          });

          // Vibração no celular se disponível
          if (navigator.vibrate) {
            navigator.vibrate([200, 100, 200]);
          }
        }
      });
      return () => unsub();
    }
  }, [selectedKidId, notificationsEnabled]);

  const requestNotificationPermission = async () => {
    if (!window.Notification) return;
    const permission = await Notification.requestPermission();
    if (permission === 'granted') {
      setNotificationsEnabled(true);
    }
  };

  const filtered = search.length > 1 
    ? kids.filter(k => (k.nome + ' ' + k.sobrenome).toLowerCase().includes(search.toLowerCase()))
    : [];

  const handleSelect = async (kidId: string) => {
    if (!activeCulto) return;
    setSelectedKidId(kidId);

    // Solicitar notificação no primeiro clique
    if (window.Notification && Notification.permission === 'default') {
      await requestNotificationPermission();
    }

    const existing = preCheckins.find(p => p.idCrianca === kidId && p.idCulto === activeCulto.id && p.status === 'pendente');

    if (existing) {
      setGenerated(existing.codigo);
      setStep(2);
      return;
    }

    const code = `KIDS-${Math.floor(1000 + Math.random() * 8999)}`;
    const newPre: Omit<PreCheckIn, 'id'> = {
      idCrianca: kidId,
      idCulto: activeCulto.id,
      codigo: code,
      status: 'pendente',
      dataHoraPreCheckin: new Date().toISOString()
    };

    await storageService.addPreCheckin(newPre);
    setGenerated(code);
    setStep(2);
  };

  if (loading) return <div className="text-center py-20 text-purple-main font-bold">Carregando...</div>;
  if (!activeCulto) return <Navigate to="/pais" />;

  return (
    <div className="min-h-screen bg-gray-light p-4 flex flex-col items-center">
      <div className="w-full max-w-lg">
        <button 
          onClick={() => step === 1 ? navigate('/pais') : setStep(1)}
          className="mb-6 mt-2 flex items-center gap-2 text-purple-main font-black uppercase text-[10px] tracking-widest"
        >
          {ICONS.ArrowLeft} Voltar
        </button>

        {step === 1 ? (
          <div className="bg-white rounded-[2.5rem] p-8 shadow-2xl border-b-6 border-purple-main animate-in slide-in-from-right duration-500">
             <h2 className="text-2xl font-black text-purple-dark mb-2 uppercase tracking-tight">Buscar Filho</h2>
             <p className="text-gray-text text-xs font-bold mb-8">Digite o nome para gerar o código.</p>

             <div className="relative mb-6">
                <span className="absolute left-5 top-1/2 -translate-y-1/2 text-gray-400">{ICONS.Search}</span>
                <input 
                  type="text"
                  placeholder="Nome da criança..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="w-full pl-14 pr-5 py-4 rounded-2xl bg-gray-light border-2 border-transparent focus:border-purple-main outline-none font-bold text-base"
                />
             </div>

             <div className="space-y-3 max-h-[350px] overflow-y-auto pr-1 custom-scrollbar">
                {filtered.map(k => (
                  <button 
                    key={k.id}
                    onClick={() => handleSelect(k.id)}
                    className="w-full flex items-center justify-between p-4 bg-purple-main/5 hover:bg-purple-main hover:text-white rounded-2xl border-2 border-transparent transition-all group"
                  >
                    <div className="text-left">
                       <p className="font-black text-sm group-hover:text-white text-purple-dark">{k.nome} {k.sobrenome}</p>
                       <p className="text-[9px] font-black uppercase opacity-60 tracking-widest group-hover:text-white">Resp: {k.responsavelNome}</p>
                    </div>
                    <div className="bg-white p-2.5 rounded-xl text-purple-main shadow-sm group-hover:scale-110 transition-transform">{ICONS.ChevronRight}</div>
                  </button>
                ))}
                {search.length > 1 && filtered.length === 0 && (
                   <div className="text-center py-10 bg-gray-50 rounded-[1.5rem] border-2 border-dashed border-gray-200">
                      <p className="text-gray-text text-xs font-bold mb-4 italic">Nenhum cadastro encontrado.</p>
                      <button 
                        onClick={() => navigate('/pais/cadastro')}
                        className="bg-yellow-main text-purple-dark px-5 py-2.5 rounded-xl font-black text-[10px] shadow-md uppercase"
                      >
                         CADASTRAR FILHO
                      </button>
                   </div>
                )}
             </div>
          </div>
        ) : (
          <div className="bg-white rounded-[2.5rem] p-8 md:p-12 shadow-2xl text-center animate-in zoom-in duration-500 relative overflow-hidden">
             <div className="absolute top-0 left-0 w-full h-3 bg-green-500" />

             <div className="bg-green-100 text-green-600 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6 text-2xl shadow-inner">
                {ICONS.CheckCircle}
             </div>

             <h2 className="text-2xl font-black text-purple-dark mb-2 uppercase">PRONTO!</h2>

             {notificationsEnabled ? (
                <div className="bg-green-50 border border-green-200 text-green-700 p-3 rounded-2xl mb-6 text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2">
                   <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse" />
                   Alertas de Chamada Ativados
                </div>
             ) : (
                <button 
                  onClick={requestNotificationPermission}
                  className="bg-yellow-50 border border-yellow-200 text-yellow-700 p-3 rounded-2xl mb-6 text-[10px] font-black uppercase tracking-widest w-full animate-bounce"
                >
                  🔔 Clique para permitir alertas no celular
                </button>
             )}

             <p className="text-gray-text font-bold mb-8 text-sm leading-tight px-2">
                Apresente este código na recepção para confirmar a entrada:
             </p>

             <div className="bg-purple-dark text-yellow-main p-8 rounded-[2rem] shadow-2xl mb-8 transform transition-transform cursor-pointer active:scale-95 select-none">
                <span className="text-[9px] font-black uppercase tracking-[0.3em] opacity-40 block mb-3">Código de Hoje</span>
                <span className="text-5xl md:text-6xl font-black tracking-widest block font-mono">{generated}</span>
             </div>

             <button 
              onClick={() => navigate('/pais')}
