             />
          </div>
       </div>

       {loading ? (
         <div className="text-center py-20 text-purple-main font-bold">Carregando base de dados...</div>
       ) : (
         <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {filtered.map(kid => (
