             <h3 className="text-sm font-black text-purple-dark uppercase tracking-widest">Evolução de quantidade de crianças por culto</h3>
          </div>

          <div className="h-[350px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 20, right: 30, left: 0, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#999', fontSize: 10, fontWeight: 'bold'}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#999', fontSize: 10, fontWeight: 'bold'}} />
                <Tooltip 
                  cursor={{fill: '#f9f9f9'}} 
                  contentStyle={{borderRadius: '20px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.1)', padding: '15px', fontSize: '12px', fontWeight: 'bold'}} 
                />
                <Bar dataKey="total" radius={[12, 12, 0, 0]} barSize={45}>
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#7E3FA0' : '#FFC800'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
       </div>
    </div>
  );
};

export default Estatisticas;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { ICONS } from '../constants';
import { Culto, CheckIn, Crianca } from '../types';

const CultosLista: React.FC = () => {
  const navigate = useNavigate();
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [cultos, setCultos] = useState<Culto[]>([]);
  const [allCheckins, setAllCheckins] = useState<CheckIn[]>([]);
  const [allKids, setAllKids] = useState<Crianca[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        const [cultosList, checkinsList, kidsList] = await Promise.all([
          storageService.getCultos(),
          storageService.getAllCheckins(),
          storageService.getCriancas()
        ]);
        setCultos(cultosList);
        setAllCheckins(checkinsList);
        setAllKids(kidsList);
      } catch (error) {
        console.error("Erro ao carregar histórico:", error);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  if (loading) {
    return <div className="text-center py-20 text-purple-main font-bold">Carregando histórico...</div>;
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
