                    <p className="mt-3 text-[10px] font-black text-gray-400">{formatPhone(kid.whatsapp)}</p>
                 </div>
              </div>
            ))}
         </div>
       )}

       {/* Modal Adicionar / Editar */}
       {isAdding && (
